    println!("Is 7 even? {}", is_even(7));
}

lessons.theory:
## If and Loops

```rust
// If expressions (can return values!)
let condition = true;
let number = if condition { 5 } else { 6 };

// loop (infinite)
loop { break; }

// while loop
while n > 0 { n -= 1; }

// for loop (iterator)
for i in 0..5 { 
    println!("{}", i); // 0 to 4
}
```

