lessons.solution:
fn print_length(s: &String) {
    println!("Length: {}", s.len());
}

fn main() {
    let text = String::from("Borrowing is cool");

    // Pass a reference
    print_length(&text);

    // text is still valid!
    println!("Text is still: {}", text);
}

