lessons.solution:
fn append_world(s: &mut String) {
    s.push_str(" World");
}

fn main() {
    // Must be mut to borrow mutably
    let mut greeting = String::from("Hello");

    // Pass mutable reference
    append_world(&mut greeting);

    println!("{}", greeting);
}
